Rule.Source:
 
import sailpoint.api.Workflower;
import sailpoint.object.Attributes;
import sailpoint.object.Application;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningPlan.AbstractRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningResult;
import sailpoint.object.QueryOptions;
import sailpoint.object.Workflow;
import sailpoint.tools.Util;
import org.apache.log4j.Logger;
import sailpoint.object.IdentityEntitlement;
import sailpoint.object.IdentityRequestItem;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import sailpoint.object.IdentityEntitlement.AggregationState;

Logger refLogger = Logger.getLogger("sailpoint.ascension.rules.afterProvisioning.Invision");

refLogger.debug("Entering AfterProvisioning For Invision");

if(plan != null) {

    refLogger.trace("plan is NOT NULL - Proceeding...");
	refLogger.debug("Printing Plan in AfterProvisioning rule: "+ plan.toXml());
	
    Identity refIdentity = plan.getIdentity();
    String identityName = refIdentity.getName();
	
	refLogger.debug("AfterProvisioning rule IdentityName: "+ identityName);

    String samAccountName = refIdentity.getAttribute("samAccountName");

    String appName = application.getName(); 

    //get identity entitlement 
	
	QueryOptions ops = new QueryOptions();
	ops.addFilter(Filter.eq("application.name", "Invision"));
	ops.addFilter(Filter.eq("identity.name", identityName));
	ops.addFilter(Filter.eq("aggregationState", "Disconnected"));
	
	List identityEntitlements = context.getObjects(IdentityEntitlement.class, ops);
	
	if (identityEntitlements !=null && identityEntitlements.size() > 0 ) {
		//check if identityEntitlement is correlated
		refLogger.debug("Disconnected Entitlements: "+ identityEntitlements.size());
		
		for (IdentityEntitlement idEntitlement : identityEntitlements) {
			idEntitlement.setAggregationState(IdentityEntitlement.AggregationState.Connected);
			idEntitlement.setAssigned(true);
			context.saveObject(idEntitlement);
			refLogger.debug("After setting idEntitlement aggregation state: "+ idEntitlement.getAggregationState().toString());
			refLogger.debug("Assigned: "+ idEntitlement.isAssigned());
		}	
	}
	
	context.commitTransaction();
	
	
	
} else {

    refLogger.trace("plan is NULL - END");

}

refLogger.trace("Exiting AfterProvisioning For Invision");
